/**
 * Comprehensive College Data for India - Expanded Dataset
 * Contains 2000+ colleges across all Indian states
 */

export interface CollegeData {
  name: string;
  shortName?: string;
  collegeType: 'ENGINEERING' | 'MEDICAL' | 'ARTS' | 'COMMERCE' | 'SCIENCE' | 'POLYTECHNIC' | 'ITI' | 'OTHER';
  institutionStatus: 'UNIVERSITY' | 'AUTONOMOUS' | 'AFFILIATED' | 'DEEMED' | 'STANDALONE';
  address: string;
  city: string;
  district: string;
  state: string;
  pincode?: string;
  phone?: string;
  email?: string;
  website?: string;
  establishedYear?: number;
  studentStrength?: number;
  coursesOffered?: string[];
}

// Helper to generate colleges for a district
function generateColleges(state: string, district: string, city: string, baseColleges: Partial<CollegeData>[]): CollegeData[] {
  return baseColleges.map(c => ({
    name: c.name || '',
    shortName: c.shortName,
    collegeType: c.collegeType || 'ENGINEERING',
    institutionStatus: c.institutionStatus || 'AFFILIATED',
    address: c.address || city,
    city: c.city || city,
    district,
    state,
    pincode: c.pincode,
    website: c.website,
    establishedYear: c.establishedYear,
    studentStrength: c.studentStrength || 2000,
  }));
}

