// Export functions
export function getExpandedCollegeCount(): number {
  let count = 0;
  for (const state in expandedCollegesByState) {
    count += expandedCollegesByState[state].length;
  }
  return count;
}

export function getExpandedStates(): string[] {
  return Object.keys(expandedCollegesByState).sort();
}

export function getExpandedCollegesByState(state: string): CollegeData[] {
  return expandedCollegesByState[state] || [];
}
